// Real venue lookup based on match_id
export function getVenue(matchId: number): string {
  const idx = VENUE_MAP[matchId];
  if (idx !== undefined && idx >= 0 && idx < STADIUMS.length) {
    return STADIUMS[idx];
  }
  // Fallback (should not happen with valid match_ids)
  return STADIUMS[matchId % STADIUMS.length];
}
